import React from "react";
import { useParams } from "react-router-dom";
import "./ProductDetail.css";

function ProductDetail({ addToCart }) {
  const { id } = useParams();

  // dummy data (same as Products)
  const products = [
    {
      id: 1,
      name: "iPhone 14",
      price: "₹70,000",
      description: "Latest Apple iPhone with A15 chip",
      img: "https://images.unsplash.com/photo-1592750475338-74b7b21085ab?w=400"
    },
    {
      id: 2,
      name: "Nike Shoes",
      price: "₹2,000",
      description: "Comfortable running shoes",
      img: "https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=400"
    }
  ];

  const product = products.find((p) => p.id === parseInt(id));
if (!product) {
  return <h2>Product not found</h2>;
}
  return (
    <div className="product-detail">
      <img src={product.img} alt={product.name} />

      <div>
        <h2>{product.name}</h2>
        <p>{product.price}</p>
        <p>{product.description}</p>

        <button onClick={() => addToCart(product)}>
          Add to Cart
        </button>

        <button>Buy Now</button>
      </div>
    </div>
  );
}

export default ProductDetail;
